import { GoogleSecurityDetails, ScanError } from "@/app/scripts/oap/types";
import { getAF_initDataCallback } from "../utils";

export const googleSecurityDetails = async (
  html: string
): Promise<GoogleSecurityDetails | ScanError> => {
  const array = getAF_initDataCallback(html, 1);
  const res = extractStrings(array);

  const dataArray = res.filter(
    // @ts-ignore
    (a) => !(a.includes("/") || a.includes("=") || !isNaN(Number(a)))
  );
  console.debug("OAP: Google security details dataArray", JSON.stringify(dataArray, null, 2));

  try {
    // @ts-ignore
    let recoveryEmail = dataArray.find((a) => a.includes("@"));
    // @ts-ignore
    const isRecoveryEmailVerified = !recoveryEmail?.includes("Verify");

    if (!isRecoveryEmailVerified) {
      // @ts-ignore
      recoveryEmail = recoveryEmail.replace("Verify", "").trim();
    }

    // @ts-ignore
    const recoveryPhoneStringIndex = dataArray.lastIndexOf("Recovery phone");
    const passwordStringIndex = dataArray.findIndex((a) =>
      // @ts-ignore
      a.includes("Password")
    );

    const recoveryPhone = dataArray[recoveryPhoneStringIndex + 1];
    const passwordLastChange = dataArray[passwordStringIndex + 1];
    const passwordLastChangeDate = parseDateAndTime(passwordLastChange);

    const res: GoogleSecurityDetails = {
      // @ts-ignore
      recoveryPhone: recoveryPhone?.includes("Add") ? undefined : recoveryPhone,
      recoveryEmail: isRecoveryEmailVerified
        ? recoveryEmail || undefined
        : undefined,
      passwordLastChange: passwordLastChangeDate,
    };

    console.debug("OAP: Google security details dataArray", JSON.stringify(dataArray, null, 2));
    const howYouSignInIndex = dataArray.findIndex((a) =>
      // @ts-ignore
      a.toLowerCase().startsWith("how you sign in to google")
    );
    console.debug("OAP: Google security details howYouSignInIndex", howYouSignInIndex);
    if (howYouSignInIndex != -1 && dataArray.length >= howYouSignInIndex) {
      const subArray = dataArray.slice(howYouSignInIndex);
      const twoStepStrings = subArray.filter((a) => {
        // @ts-ignore
        return a.includes("2-Step Verification");
      });
      const isOff = twoStepStrings.some((a) => {
        // @ts-ignore
        return a.includes("off") || a.includes("turned off");
      });
      res.twoFactorStatus = isOff ? "off" : "on";
    }

    console.debug("OAP: Google security details", JSON.stringify(res, null, 2));
    return res;
  } catch (err) {
    return {
      error: "OAP: Google error scraping security details:" + (err as Error).message,
      stack: (err as Error).stack,
    };
  }
};

const extractStrings = (data: unknown) => {
  let results = [];

  if (Array.isArray(data)) {
    // If the data is an array, iterate over its elements
    for (let item of data) {
      results = results.concat(extractStrings(item));
    }
  } else if (typeof data === "object" && data !== null) {
    // If the data is an object (but not null), iterate over its values
    for (let key in data) {
      results = results.concat(extractStrings(data[key]));
    }
  } else if (
    typeof data === "string" &&
    data.toLowerCase() !== "null" &&
    data.toLowerCase() !== "undefined"
  ) {
    // If the data is a string (but not "null" or "undefined"), add it to the results
    //@ts-ignore
    results.push(data);
  }

  return results;
};

// Last changed 7 Jun 2022
// Last changed 7 Jan
// TODO: test with password change dates that are pretty recent (minutes ago)
const parseDateAndTime = (dateStr: string): Date | undefined => {
  dateStr = dateStr.trim().toLowerCase();
  // strip the "last changed" prefix
  dateStr = dateStr.replace("last changed ", "").trim();
  // check if the dateStr contains a year
  if (dateStr.includes(" ")) {
    const dateParts = dateStr.split(" ");
    if (dateParts.length == 2) {
      // No year, we need to use the current year
      dateStr = `${dateStr} ${new Date().getFullYear()}`;
    }
  }
  // parse the date
  const dateObj = new Date(dateStr);
  if (isNaN(dateObj.getTime())) {
    return undefined;
  }
  return dateObj;
};
