import { GoogleThirdPartyApp, ScanError } from "@/app/scripts/oap/types";
import { getAF_initDataCallback } from "../utils";


export const googleThirdPartyApps = async (html: string): Promise<GoogleThirdPartyApp[] | ScanError> => {
  const data = getAF_initDataCallback(html, 1);
  if (!data || !Array.isArray(data)) {
    return [];
  }

  if (data.length === 0) {
    return [];
  }

  const dataArr: any = data[0];
  const checkPermissionType = (a: unknown) => {
    return Array.isArray(a) && a[4] !== undefined && a[4][0] === null;
  };

  const { signInWithGoogle, accessToAnyAccountAccess } = dataArr.reduce(
    (acc: Record<string, Array<unknown>>, v: unknown) => {
      (checkPermissionType(v)
        ? acc.accessToAnyAccountAccess
        : acc.signInWithGoogle
      ).push(v);
      return acc;
    },
    { signInWithGoogle: [], accessToAnyAccountAccess: [] }
  );

  try {
    const appsPromises = accessToAnyAccountAccess
      .map((app: Array<unknown>) => {
        const baseURL = "https://myaccount.google.com/connections/overview/";
        return baseURL + app[0];
      })
      .map((url: string) =>
        fetch(url, {
          body: null,
          method: "GET",
          mode: "cors",
          credentials: "include",
        })
      );

    const resArray = await Promise.all(appsPromises);
    const textPromiss = resArray.map((res: any) => res.text());

    const htmlData = await Promise.all(textPromiss);

    const afData = htmlData.map((txt: string) => {
      return getAF_initDataCallback(txt, 1);
    });

    console.debug("OAP: Google third party apps", {
      signInWithGoogle,
      afData,
    });
    const processed = processData([...signInWithGoogle, ...afData]);
    console.debug("OAP: Google third party apps processed", JSON.stringify(processed, null, 2));
    return processed;
  } catch (err) {
    console.error("OAP: Google error scraping third party apps", err);
    return { error: "OAP: Google error scraping third party apps:" + (err as Error).message, stack: (err as Error).stack };
  }
};

function processData(data: Array<unknown>): Array<GoogleThirdPartyApp> {
  let processedData: any = [];

  processedData = [
    ...processedData,
    ...data
      // @ts-ignore
      .filter((innerList: any[][]) => !!innerList?.[1]?.[0])
      // @ts-ignore
      .map((innerList: any[][][][][]) => {              
        const appId = innerList[0];
        // console.debug("OAP: Google third party apps id", id);
        const name = innerList?.[1]?.[0] || null;
        if (!name) {
          console.log("name is null", innerList);
        }

        const homePage = innerList?.[1]?.[5] || null;

        const accessGivenOnTS = innerList?.[2]?.[0]?.[1]?.[0] || null;
        const accessGivenOn =
          typeof accessGivenOnTS === "number"
            ? new Date(accessGivenOnTS * 1000).toISOString()
            : null;

        const accessGivenTo =
          innerList?.[2]?.[0]?.[5]?.[0]?.[4]?.[0] || homePage;

        let permissionsArray = innerList?.[2]?.[0]?.[5]?.[0]?.[6];
        permissionsArray = permissionsArray
          ? permissionsArray.map((p: any) => {
              return {
                title: p?.[0] || "",
                description: p?.[1] || "",
                weight: 1,
              };
            })
          : [
              {
                title: "Basic account info",
                description: "",
                weight: 0,
              },
            ];

        return {
          id: appId,
          name,
          homePage,
          permissions: permissionsArray,
          accessGivenOn,
          accessGivenTo,
        };
      }),
  ];

  return processedData;
}
