import { googleSecurityDetails } from "./security";
import { googlePersonalInfo } from "./personal-info";
import { googleProfileInfo } from "./profile";
import { googleThirdPartyApps } from "./third-party-apps";
import {
  buildHeaders,
  checkForCancellation,
  createDebugScanError,
  extractGoogleAuthQuery,
  shouldFailRandomly,
} from "./utils";
import {
  GoogleDeviceSessions,
  GoogleScanResults,
  GoogleScanType,
  isScanError,
  ScanError,
} from "@/app/scripts/oap/types";
import { scrapeDeviceSessionFromPage, scrapeDeviceSessionIDs } from "./devices";

const fetchHtml = async (url: string): Promise<string | undefined> => {
  const headers = buildHeaders();
  console.debug("OAP: Google fetching url", url);
  try {
    const res = await fetch(url, {
      headers,
      redirect: "follow", // Explicitly follow redirects
    });
    const html = await res.text();
    return html;
  } catch (err) {
    console.error("OAP: Google error fetching url", { url, err });
    return undefined;
  }
};

const googleBaseURL = "https://myaccount.google.com/";

export async function runGoogleOAPCheck(
  pageUrl: string,
  ignore: GoogleScanType[] = [],
  debugRandomFailure: boolean = false
): Promise<{ scanResults: GoogleScanResults; deviceIDs: string[] }> {
  let scanResults: GoogleScanResults = {};

  console.debug("OAP: runGoogleOAPCheck called with debugRandomFailure =", debugRandomFailure);

  // scrape third party apps
  if (!ignore.includes("thirdPartyApps")) {
    const thirdPartyAppsScanResults = await runGoogleThirdpartyAppsCheck(debugRandomFailure);
    scanResults = { ...scanResults, ...thirdPartyAppsScanResults };
    checkForCancellation();
  }

  // scrape profile & visibility
  if (!ignore.includes("profileInfo")) {
    const profileInfoScanResults = await runGoogleProfileInfoCheck(debugRandomFailure);
    scanResults = { ...scanResults, ...profileInfoScanResults };

    checkForCancellation();
  }

  // scrape security details
  if (!ignore.includes("securityDetails")) {
    const securityDetailsScanResults = await runGoogleSecurityDetailsCheck(debugRandomFailure);
    scanResults = { ...scanResults, ...securityDetailsScanResults };

    checkForCancellation();
  }

  // scrape device IDs, will be used later to scan device activity for each device
  let deviceIDs: string[] = [];
  if (!ignore.includes("deviceSessions")) {
    // Check for debug random failure
    if (shouldFailRandomly(debugRandomFailure)) {
      console.warn("OAP: [DEBUG] Simulating random failure for deviceSessions");
      scanResults.deviceSessions = createDebugScanError("deviceSessions");
    } else {
      try {
        deviceIDs = await scrapeDeviceSessionIDs();
        console.debug(
          "OAP: Scanned Google device session IDs",
          JSON.stringify(deviceIDs, null, 2)
        );
      } catch (err) {
        console.error("OAP: Google error scraping device session IDs", err);
        scanResults.deviceSessions = { error: "OAP: Google error scraping device session IDs: " + (err as Error).message, stack: (err as Error).stack };
      } finally {
        checkForCancellation();
      }
    }
  }

  console.debug("OAP: Completed Google OAP check", JSON.stringify(scanResults, null, 2));

  return { scanResults, deviceIDs };
}

/**
 * Runs ONLY the third party apps check (for the "Rescan this" button)
 */
export async function runGoogleThirdpartyAppsCheck(debugRandomFailure: boolean = false): Promise<GoogleScanResults> {
  const { rapt } = await extractGoogleAuthQuery();
  if (!!rapt) {
    console.debug(
      "OAP: Google security details check: can do fetch + AF_initDataCallback"
    );
  }

  const scanResults: GoogleScanResults = {};

  // Check for debug random failure
  if (shouldFailRandomly(debugRandomFailure)) {
    console.warn("OAP: [DEBUG] Simulating random failure for thirdPartyApps");
    scanResults.thirdPartyApps = createDebugScanError("thirdPartyApps");
    return scanResults;
  }

  // scrape third party apps
  const slug = "connections";
  const connectionsHtml = await fetchHtml(`${googleBaseURL}${slug}`);
  if (!connectionsHtml) {
    scanResults.thirdPartyApps = { error: "OAP: Google error fetching connections html" };
  } else {
    const thirdPartyApps = await googleThirdPartyApps(connectionsHtml);
    scanResults.thirdPartyApps = thirdPartyApps;
    if (!isScanError(thirdPartyApps)) {
      console.debug(
        "OAP: Scanned Google third party apps",
        JSON.stringify(thirdPartyApps, null, 2)
      );
    }
  }

  return scanResults;
}

