export async function runGoogleDeviceIDCheck(
  deviceID: string
): Promise<GoogleScanResults> {
  const { rapt } = await extractGoogleAuthQuery();
  if (!!rapt) {
    console.debug(
      "OAP: Google security details check: can do fetch + AF_initDataCallback"
    );
  }

  let scanResults: GoogleScanResults = {};

  const deviceSession = await scrapeDeviceSessionFromPage(deviceID);
  if (isScanError(deviceSession)) {
    scanResults.deviceSessions = deviceSession;
  } else if (deviceSession === undefined) {
    scanResults.deviceSessions = {};
  } else {
    scanResults.deviceSessions = {
      [deviceID]: deviceSession,
    } as unknown as GoogleDeviceSessions;
  }
  return scanResults;
}
