export type DeviceSession = {
  sessionId: string;
  pending: boolean;
  deviceName?: string;
  deviceType?: string;
  isThisDevice: boolean;
  firstSeen?: string;
  lastSeen?: string;
  location?: string;
  formFactorNum?: number;
  osNum?: number;
};

type DeviceSessions = Record<string, DeviceSession>;

export const scrapeDeviceSessionIDs = async (): Promise<string[]> => {
  const securityPageLink = document.querySelector('a[href^="security"]');
  if (!securityPageLink) {
    throw new Error("OAP: Google security page link not found");
  }
  // click it
  (securityPageLink as HTMLElement).click();

  // Wait for security page to load by looking for device activity link
  await waitForElement('a[href^="device-activity"]', 10_000);
  console.debug("OAP: Google security page loaded");

  // find a link with the href that starts with device-activity
  const deviceActivityLink = document.querySelector(
    'a[href^="device-activity"]'
  );
  if (!deviceActivityLink) {
    throw new Error("OAP: Google device activity link not found");
  }

  // click it
  (deviceActivityLink as HTMLAnchorElement).click();

  // selector for the tag <c-wiz> that has the attribute jsrenderer (don't care about what the value is)
  await waitForElement("c-wiz[jsrenderer]", 15_000);

  console.debug("OAP: Google device activity page loaded with content");

  // Additional wait for any async content loading
  await new Promise((resolve) => setTimeout(resolve, 6000));
  await waitForElement('c-wiz[jsrenderer][style*="visibility: visible"]');

  const sessions: DeviceSessions = {};
  const deviceIDs: string[] = [];

  try {
    console.debug("OAP: scrapeDeviceSessions: Scraping device sessions");
    const cwizElems = document.querySelectorAll(
      'c-wiz[jsrenderer][style*="visibility: visible"]'
    );
    if (cwizElems.length === 0) {
      console.error("OAP: scrapeDeviceSessions: cwiz element not found");
      throw new Error(
        "OAP: Google scrapeDeviceSessions: cwiz element not found"
      );
    }

    for (let i = 0; i < cwizElems.length; i++) {
      const cwizElem = cwizElems[i];
      console.debug("OAP: scrapeDeviceSessions: Found cwiz element", cwizElem);
    }

    const cwizElem = cwizElems[0];
    // console.debug("OAP: scrapeDeviceSessions: Found cwiz element", cwizElems);

    // Find all device sections - they are divs with the specific class pattern
    const deviceSections = cwizElem.querySelectorAll(
      ".VfPpkd-WsjYwc.VfPpkd-WsjYwc-OWXEXe-INsAgc.KC1dQ.Usd1Ac.AaN0Dd.F2KCCe.NkyfNe.hG48Q"
    );

    for (let sectionIdx = 0; sectionIdx < deviceSections.length; sectionIdx++) {
      const section = deviceSections[sectionIdx];

      // Find all device entries within this section
      const deviceElements = section.querySelectorAll(
        "li.K6ZZTd.iUwXVd.bs2km.t7ce4c"
      );

      for (let deviceIdx = 0; deviceIdx < deviceElements.length; deviceIdx++) {
        const deviceElement = deviceElements[deviceIdx];

        try {
          // Extract device ID from the link's data-device-id attribute
          const linkElement = deviceElement.querySelector(
            "a[data-device-id]"
          ) as HTMLAnchorElement;
          if (!linkElement) {
            console.warn(
              `OAP: scrapeDeviceSessions/deviceElements/${deviceIdx}: No link element found for section ${sectionIdx} device ${deviceIdx}`
            );
            continue;
          }

          const deviceId = linkElement.getAttribute("data-device-id");
          if (!deviceId) {
            console.warn(
              `OAP: scrapeDeviceSessions/deviceElements/${deviceIdx}: No device ID found for section ${sectionIdx} device ${deviceIdx}`
            );
            continue;
          }
          deviceIDs.push(deviceId);

          // try {
          //   const sessionDetails = await scrapeDeviceSession(linkElement);
          //   sessions[deviceId] = sessionDetails;
          // } catch (sessionErr) {
          //   console.error(
          //     `OAP: scrapeDeviceSessions/deviceElements/${deviceIdx}: Error scraping device session for section ${sectionIdx} device ${deviceIdx}`,
          //     sessionErr
          //   );
          // } finally {
          //   // Go back to the device activity page
          //   const backButton = document.querySelector(
          //     'div[role="button"][aria-label="Back"]'
          //   );
          //   if (backButton) {
          //     (backButton as HTMLDivElement).click();
          //   } else {
          //     window.history.back();
          //   }
          //   await sleep(1_000);
          // }
        } catch (deviceElemErr) {
          console.error(
            `OAP: scrapeDeviceSessions/deviceElements/${deviceIdx}: Failed to scrape device session: `,
            deviceElemErr
          );
        }
      }

      console.debug(
        `OAP: scrapeDeviceSessions/deviceSections/${sectionIdx}: Found ${deviceIDs.length} device IDs`,
        deviceIDs
      );
    }
  } catch (error) {
    console.error(
      "OAP: scrapeDeviceSessions: Error scraping device sessions",
      error
    );
  }

  // console.log("OAP: scrapeDeviceSessions: Scraped all device sessions", {
  //   count: Object.keys(sessions).length,
  //   sessions,
  // });

  console.log("OAP: scrapeDeviceSessions: Scraped all device session IDs", {
    count: deviceIDs.length,
    deviceIDs,
  });

  return deviceIDs;
};

// form factors:
// 1 - macbook
// 2 - phone
// 8 - TV

// oses:
// 2 - macos
// 5 - iOS
// 4 - android tv

export const scrapeDeviceSessionFromPage = async (
  deviceId: string
): Promise<DeviceSession | undefined | ScanError> => {
  try {
    let deviceName: string | undefined;
    let formFactorNum: number | undefined;
    let osNum: number | undefined;
    let deviceType: string | undefined;
    let firstSeen: string | undefined;
    let lastSeen: string | undefined;
    let location: string | undefined;
    let isThisDevice: boolean = false;
    let isSignedOut: boolean = false;
  
    //<c-wiz jsrenderer="XKnbkd" data-is-webview="false" jsshadow="" jsdata="deferred-c16" data-p="%.@.0,null,&quot;IKXKmfT5i-T1NQ&quot;]" data-node-index="1;0" jsmodel="hc6Ubd raOC7d" c-wiz="">
    // find the c-wiz element that has a data-p attribute that contains the deviceId. E.g in the example above, the deviceId is "IKXKmfT5i-T1NQ"
    const cwizElems = document.querySelectorAll(`c-wiz`);
    if (cwizElems.length === 0) {
      throw new Error("OAP: scrapeDeviceSession: No cwiz element found");
    }
  
    // find the c-wiz element that has a data-help-context=DEVICE_ACTIVITY_SCREEN attribute that contains the deviceId. E.g in the example above, the deviceId is "IKXKmfT5i-T1NQ"
    let cwizElem: Element | undefined;
    for (let i = 0; i < cwizElems.length; i++) {
      const elem = cwizElems[i] as HTMLElement;
      // console.debug("OAP: scrapeDeviceSession: looking for deviceId", elem.dataset.p, deviceId);
      // if (elem.dataset.p?.includes(deviceId)) {
      //   cwizElem = elem;
      //   break;
      // }
      if (
        elem.getAttribute("data-help-context") === "DEVICE_ACTIVITY_SCREEN" &&
        elem.dataset.p?.includes(deviceId)
      ) {
        cwizElem = elem;
        break;
      }
    }
  
    if (!cwizElem) {
      throw new Error(
        "OAP: scrapeDeviceSession: No cwiz element found for deviceId: " +
          deviceId
      );
    }
  
    console.debug(
      "OAP: scrapeDeviceSessionFromPage: Found cwiz element",
      cwizElem
    );
  
    const formFactorDiv = await scrapeDomChain(cwizElem, [
      "div.C2O4Ve",
      "div.D6y2ld",
      "div.kZHi8.EMT5zb",
    ]);
    if (formFactorDiv) {
      const formFactorStr = (
        formFactorDiv as HTMLDivElement
      ).dataset.formFactor?.trim();
      if (formFactorStr) {
        formFactorNum = parseInt(formFactorStr);
        if (isNaN(formFactorNum)) {
          formFactorNum = undefined;
          console.warn(
            "OAP: scrapeDeviceSession: Invalid form factor number",
            formFactorStr
          );
        } else {
          console.debug(
            "OAP: scrapeDeviceSession: Form factor number",
            formFactorNum
          );
        }
      }
  
      const osStr = (formFactorDiv as HTMLDivElement).dataset.os?.trim();
      if (osStr) {
        osNum = parseInt(osStr);
        if (isNaN(osNum)) {
          osNum = undefined;
          console.warn("OAP: scrapeDeviceSession: Invalid OS number", osStr);
        } else {
          console.debug("OAP: scrapeDeviceSession: OS number", osNum);
        }
      }
    }
  
    const deviceTypeDiv = await scrapeDomChain(cwizElem, [
      "div.C2O4Ve",
      "div.FVYsnd",
      "div[role='heading']",
    ]);
    if (deviceTypeDiv) {
      deviceType = (deviceTypeDiv as HTMLDivElement).textContent?.trim() || "";
    }
  
    const deviceNameDiv = await scrapeDomChain(cwizElem, [
      "div.C2O4Ve",
      "div.FVYsnd",
      "div:nth-child(2)",
    ]);
    if (deviceNameDiv) {
      deviceName = (deviceNameDiv as HTMLDivElement).textContent?.trim() || "";
    }
  
    const locationAndLastSeenParentDiv = await scrapeDomChain(cwizElem, [
      "div.C2O4Ve",
      "div.tHVeec",
    ]);
    if (locationAndLastSeenParentDiv) {
      if (locationAndLastSeenParentDiv.childNodes.length == 2) {
        const locationDiv = locationAndLastSeenParentDiv.childNodes[0];
        location = (locationDiv as HTMLDivElement).textContent?.trim() || "";
      }
  
      const lastSeenDiv =
        locationAndLastSeenParentDiv.childNodes[
          locationAndLastSeenParentDiv.childNodes.length - 1
        ];
      if (lastSeenDiv.textContent?.toLowerCase().includes("this device")) {
        isThisDevice = true;
      } else {
        if (lastSeenDiv.textContent?.toLowerCase().includes("learn more")) {
          lastSeen = undefined;
        } else {
          lastSeen = lastSeenDiv.textContent ?? "";
        }
      }
  
      for (let i = 0; i < locationAndLastSeenParentDiv?.childNodes.length; i++) {
        const childNode = locationAndLastSeenParentDiv.childNodes[i];
        if (
          childNode.textContent?.toLowerCase().includes("your current session")
        ) {
          isThisDevice = true;
        } else if (childNode.textContent?.toLowerCase().includes("signed out")) {
          isSignedOut = true;
        }
      }
    }
  
    if (isSignedOut) {
      return undefined;
    }
  
    const firstSeenDiv = await scrapeDomChain(cwizElem, [
      "div.C2O4Ve",
      "div.cIEMOb",
      "span:last-child",
    ]);
    if (firstSeenDiv) {
      let firstSeenText = firstSeenDiv.textContent?.trim() || "";
      firstSeenText = firstSeenText.replace("First sign-in:", "").trim();
      firstSeen = firstSeenText;
    }
  
    return {
      deviceName,
      deviceType,
      location,
      sessionId: deviceId,
      isThisDevice,
      firstSeen,
      lastSeen,
      formFactorNum,
      osNum,
      pending: false,
    };  
  } catch (error) {
    return {
      error: "OAP: scrapeDeviceSession: Error scraping device session: " + (error as Error).message,
      stack: (error as Error).stack,
    };
  }
};

export const runDeleteDeviceSession = async (
  deviceId: string
): Promise<boolean> => {
  const cwizElems = document.querySelectorAll(`c-wiz`);
  if (cwizElems.length === 0) {
    throw new Error("OAP: scrapeDeviceSession: No cwiz element found");
  }

  // find the c-wiz element that has a data-help-context=DEVICE_ACTIVITY_SCREEN attribute that contains the deviceId. E.g in the example above, the deviceId is "IKXKmfT5i-T1NQ"
  let cwizElem: Element | undefined;
  for (let i = 0; i < cwizElems.length; i++) {
    const elem = cwizElems[i] as HTMLElement;
    if (
      elem.getAttribute("data-help-context") === "DEVICE_ACTIVITY_SCREEN" &&
      elem.dataset.p?.includes(deviceId)
    ) {
      cwizElem = elem;
      break;
    }
  }

  if (!cwizElem) {
    throw new Error(
      "OAP: scrapeDeviceSession: No cwiz element found for deviceId: " +
        deviceId
    );
  }

  // find and click the sign out button
  const signoutTextSelector = "span.Rju2Ue-TfeOUb-V67aGc";
  const signoutElem = cwizElem.querySelector(signoutTextSelector);
  if (!signoutElem) {
    throw new Error("OAP: scrapeDeviceSession: No sign out element found");
  }
  (signoutElem as HTMLElement).click();

  // sleep for 2 seconds
  await new Promise((resolve) => setTimeout(resolve, 500));
  // wait for element (modal) that has a data-cancelids attribute
  const signoutModal = await waitForElement("div[data-cancelids]", 5_000);
  if (!signoutModal) {
    throw new Error("OAP: scrapeDeviceSession: No cancel modal found");
  }

  const cancelId = signoutModal.getAttribute("data-cancelids");
  if (!cancelId) {
    throw new Error("OAP: scrapeDeviceSession: No cancel id found");
  }

  const signoutActionBtns = signoutModal.querySelectorAll("button[data-id]");
  if (!signoutActionBtns) {
    throw new Error("OAP: scrapeDeviceSession: No sign out button found");
  }

  let signOutBtn: HTMLElement | undefined;
  for (let i = 0; i < signoutActionBtns.length; i++) {
    const btn = signoutActionBtns[i] as HTMLElement;
    const id = btn.getAttribute("data-id");
    if (id !== cancelId) {
      signOutBtn = btn;
      break;
    }
  }
  if (!signOutBtn) {
    throw new Error("OAP: scrapeDeviceSession: No sign out button found");
  }

  console.debug("OAP: scrapeDeviceSession: Clicking sign out span", signOutBtn);
  (signOutBtn as HTMLElement).click();
  return true;
};

async function scrapeDomChain(
  rootElement: Element,
  selectorChain: string[]
): Promise<Element | null> {
  const combinedSelector = selectorChain
    .filter((s) => s.trim() !== "")
    .join(" ");
  if (!combinedSelector) {
    return null;
  }
  return rootElement.querySelector(combinedSelector);
}
