export async function extractGoogleAuthQuery(): Promise<{
  baseURL: string
  rapt: string
  authQuery: string
}> {
  // wait for window.WIZ_global_data to be defined.
  // @ts-ignore
  while (!window.WIZ_global_data) {
    console.debug('OAP: Waiting for window.WIZ_global_data to be defined')
    await new Promise((resolve) => setTimeout(resolve, 1000))
  }

  // @ts-ignore
  const identifier = window.WIZ_global_data.oPEP7c
  // @ts-ignore
  const innerAccountNumber = window.IJ_values[3]
  // @ts-ignore
  const baseURL = window.IJ_values[4]
  // @ts-ignore
  const rapt = window.WIZ_global_data.Dbw5Ud

  console.debug('OAP: Google identifier', {
    identifier,
    rapt,
    innerAccountNumber,
    baseURL,
  })

  const continueLink = `https://myaccount.google.com/security?rapt=${rapt}`
  const authQuery = `?authuser=${innerAccountNumber}&continue=${encodeURIComponent(
    continueLink
  )}&rapt=${rapt}`

  return { baseURL, rapt, authQuery }
}

export function buildHeaders(): Record<string, string> {
  return {
    Accept: 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
    'Accept-Encoding': 'gzip, deflate, br',
    'Accept-Language': 'en-US,en;q=0.9',
    Connection: 'keep-alive',
    Host: 'myaccount.google.com',
    'User-Agent': window.navigator.userAgent,
    Cookie: window.document.cookie,
  }
}

export async function setScanInProgress(inProgress: boolean) {
  // @ts-ignore
  window.scanInProgress = inProgress
}

export async function checkForCancellation() {
  console.debug('OAP: Checking for cancellation', {
    // @ts-ignore
    scanInProgress: window.scanInProgress,
  })
  // @ts-ignore
  if (window.scanInProgress === false) {
    throw new Error('OAP: Scan cancelled')
  }
}

/**
 * Randomly decide if a scan should fail (50% chance)
 * Only fails if debug mode is enabled (passed as parameter)
 * This runs in MAIN world context, so it cannot access chrome.storage directly
 */
export function shouldFailRandomly(debugEnabled: boolean): boolean {
  if (!debugEnabled) {
    return false
  }

  // 50% chance of failure
  const shouldFail = Math.random() < 0.50
  console.debug('OAP: shouldFailRandomly check', { debugEnabled, shouldFail })
  return shouldFail
}

/**
 * Create a debug scan error
 */
export function createDebugScanError(scanType: string): { error: string; stack?: string } {
  return {
    error: `OAP: [DEBUG] Simulated random failure for ${scanType}`,
    stack: new Error().stack
  }
}