export const getAF_initDataCallback = (
  html: string,
  hash: 1 | 2,
  ds: 0 | 1 = 0
): Array<unknown> | undefined => {
  let array;
  const startString = escapeRegex(
    `AF_initDataCallback({key: 'ds:${ds}', hash: '${hash}', data:`
  );
  const endString = ", sideChannel";
  const regex = new RegExp(`${startString}(.*?)${endString}`, "s");

  const data = html.match(regex)?.[1];
  if (data) {
    const isParsable = _isJsonString(data);
    if (isParsable) {
      array = JSON.parse(data);
      return array;
    } else {
      throw new Error("[ERROR] getAF_initDataCallback: JSON parse");
    }
  } else {
    throw new Error(
      "[ERROR] getAF_initDataCallback: couldn't get AF_initDataCallback"
    );
  }
};

const escapeRegex = (string: string) => {
  return string.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"); // $& means the whole matched string
};

const _isJsonString = (str: string) => {
  try {
    JSON.parse(str);
  } catch (e) {
    //   console.error(e);
    return false;
  }
  return true;
};

export const pruneEmpty = (obj: { [key: string]: string }): unknown => {
  return (function prune(current) {
    for (let key in current) {
      const value = current[key];
      if (
        value === undefined ||
        value === null ||
        (typeof value === "string" && value === "") ||
        (typeof value === "object" && _isEmpty(prune(value))) ||
        (Array.isArray(value) && value.length === 0)
      ) {
        delete current[key];
      }
    }
    // remove any leftover undefined values from the delete
    // operation on an array
    if (Array.isArray(current)) {
      pull(current, undefined);
    }

    return current;
  })(JSON.parse(JSON.stringify(obj))); // Do not modify the original object, create a clone instead
};

const _isEmpty = (value: any) => {
  if (value === null || value === undefined) {
    return true;
  }

  // Check for string, array, and array-like objects
  if (
    typeof value === "string" ||
    Array.isArray(value) ||
    (value.hasOwnProperty("length") && typeof value.length === "number")
  ) {
    return value.length === 0;
  }

  // Check for Map and Set
  if (value instanceof Map || value instanceof Set) {
    return value.size === 0;
  }

  // Check for objects
  for (let key in value) {
    if (value.hasOwnProperty(key)) {
      return false;
    }
  }

  return true;
};

const pull = (array: unknown[], ...values: unknown[]): unknown[] => {
  let index = 0;
  while (index < array.length) {
    if (
      values.includes(array[index]) ||
      (Number.isNaN(array[index]) && values.some((v) => Number.isNaN(v)))
    ) {
      array.splice(index, 1);
    } else {
      index++;
    }
  }
  return array;
};

export type TimeDifference = {
  years: number;
  months: number;
  days: number;
};

export function getTimeDifferenceFromToday(year: number): TimeDifference {
  const today = new Date();
  const givenYearDate = new Date(year, 0, 1); // January 1 of the given year

  let yearsDifference = today.getFullYear() - year;
  let monthsDifference = today.getMonth();
  let daysDifference = today.getDate() - 1; // Subtracting 1 because we started from January 1

  if (givenYearDate > today) {
    // If the given year is in the future
    yearsDifference = -yearsDifference;
    monthsDifference = -monthsDifference;
    daysDifference = -daysDifference;
  }

  return {
    years: yearsDifference,
    months: monthsDifference,
    days: daysDifference,
  };
}

// Replace your fixed timeouts with element-based waiting
export async function waitForElement(selector: string, timeout = 10000): Promise<Element> {
  return new Promise((resolve, reject) => {
    const startTime = Date.now();
    
    const checkForElement = () => {
      const element = document.querySelector(selector);
      if (element) {
        resolve(element);
        return;
      }
      
      if (Date.now() - startTime > timeout) {
        reject(new Error(`Element ${selector} not found within ${timeout}ms`));
        return;
      }
      
      setTimeout(checkForElement, 100);
    };
    
    checkForElement();
  });
}
