import { GoogleThirdPartyApp } from "@/app/scripts/oap/types";
import { waitForElement } from "../utils";

export async function runDeleteConnection(app: GoogleThirdPartyApp): Promise<boolean> {
  console.debug("OAP: Starting to delete connected app", app.name);
  const connectionLinks = document.querySelectorAll(
    'ul.u7hyyf > li.K6ZZTd a[href^="connections/overview/"]'
  );
  if (connectionLinks.length === 0) {
    throw new Error("OAP: Google connections links not found");
  }

  console.debug("OAP: Found", connectionLinks.length, "connections links");
  let targetLink: HTMLAnchorElement | null = null;
  for (let i = 0; i < connectionLinks.length; i++) {
    const connectionLink = connectionLinks[i] as HTMLAnchorElement;
    // Find any descendant div that has text content equal to the app name
    const appNameDiv = connectionLink.querySelector("div.mMsbvc");
    console.debug("OAP: App name div", (appNameDiv as HTMLDivElement).innerText?.trim());
    if (!appNameDiv) {
      continue;
    }
    if ((appNameDiv as HTMLDivElement).innerText?.trim() === app.name) {
      console.debug("OAP: Google target link found", connectionLink.href);
      targetLink = connectionLink;
      break;
    }
  }

  if (!targetLink) {
    throw new Error("OAP: Google target link not found");
  }

  console.debug("OAP: Clicking target link", targetLink.href);
  targetLink?.click();

  //   <div class="MP7fB" jsname="BW4o6d" data-name="Bedtime Story AI" data-key="AXgE0HP_oT0QkteP40ZaGUGXXAY2XYYkNSHeWG_Wy0W-L4a414Qu_O8YwOMvqHJGJUYdrziS0KHTp8Zrw96ITCz7e5U" aria-hidden="false" role="button" tabindex="0"><div class="OZ7tnf"><div class="edUmvf iUwXVd"><ul class="u7hyyf"><li class="K6ZZTd iUwXVd bs2km"><div class="iAwpk lY6Rwe"><div class="eP6Eff"><div class="PLEKud"><img src="https://www.gstatic.com/identity/accountsettings/thirdpartymanagement/DeleteAll_2770596f56bf9b965509f40bd0b330ad.svg" alt="" role="presentation" height="48" width="48" data-iml="747085.900000006"></div></div><div class="GqRghe tXqPBe hv7wl"><div class="mMsbvc "><div class="r8f2z">Delete all connections that you have with Bedtime Story AI</div></div><div class="xsr7od"><div class="Ippjgd">You can delete the access that you’ve given to Bedtime Story AI and Google</div></div></div><div class="kvjuQc biRLo"><div class="DnDl8e"><span class="notranslate" aria-hidden="true"><svg width="24" height="24" viewBox="0 0 24 24" focusable="false" class=" NMm5M hhikbc" aria-hidden="true"><path d="M9.71 18.71l-1.42-1.42 5.3-5.29-5.3-5.29 1.42-1.42 6.7 6.71z"></path></svg></span></div></div></div><hr class="ejHzw xBaWmd BW2dib FTkAE mFZYMc"></li></ul><hr class="XLj9Xd xBaWmd BW2dib FTkAE mFZYMc"></div></div></div>
  const selector = `div.MP7fB[data-name="${app.name}"]`;

  // wait for the page to load
  await waitForElement(selector, 5_000);
  console.debug("OAP: Found selector for delete button", selector);

  const deleteButton = document.querySelector(selector);
  if (!deleteButton) {
    throw new Error("OAP: Google delete button not found");
  }

  console.debug("OAP: Clicking delete button");
  (deleteButton as HTMLElement).click();

  // wait for the modal to show up and then click the 'confirm' button
  // button with data-mdc-dialog-action="ok"
  await waitForElement('button[data-mdc-dialog-action="ok"]', 5_000);
  const confirmButton = document.querySelector(
    'button[data-mdc-dialog-action="ok"]'
  );
  if (!confirmButton) {
    throw new Error("OAP: Google confirm button not found");
  }
  (confirmButton as HTMLElement).click();

  // wait 2 seconds
  await new Promise((resolve) => setTimeout(resolve, 2_000));
  console.debug(`OAP: Successfuly deleted connection to ${app.name}`);
  return true;
}
