import {
  GoogleProfileInfo,
  GoogleProfileInfoVisibility,
  ScanError,
} from "@/app/scripts/oap/types";
import { getAF_initDataCallback } from "../utils";

export const googleProfileInfo = async (
  html: string
): Promise<GoogleProfileInfo | undefined | ScanError> => {
  const profile: GoogleProfileInfo = {};
  try {
    const array = getAF_initDataCallback(html, 2, 1);
    if (!array) {
      return { error: "OAP: Google error scraping profile info: array is null" };
    }
    const flattenDeepRes = array?.flat(Infinity);

    console.debug('OAP: googleProfileInfo: flattenDeepRes', JSON.stringify(flattenDeepRes, null, 2));

    if (!flattenDeepRes || flattenDeepRes.length === 0) {
      console.warn("OAP: googleProfile: flattenDeepRes is null or empty");
      return undefined;
    }

    const nameIdx = flattenDeepRes.findIndex(
      (e) => typeof e === "string" && e === "Name"
    );
    if (nameIdx !== -1) {
      const nameValueIdx = nameIdx + 35;
      const name = nameValueIdx < flattenDeepRes.length
        ? flattenDeepRes[nameValueIdx]
        : null;
      const visibilityIdx = nameIdx + 51;
      const visibilityStr = visibilityIdx >= 0 && visibilityIdx < flattenDeepRes.length
        ? flattenDeepRes[visibilityIdx]
        : null;
      const nameVisibility =
        visibilityStr && typeof visibilityStr === "string" && visibilityStr.toLowerCase().includes("visible to anyone")
        ? "public"
        : "private";

      if (name && typeof name === "string") {
        profile.name = {
          value: name,
          visibility: nameVisibility,
        };
      }
    }

    const profilePictureTitleIndex =
      flattenDeepRes.lastIndexOf("Profile picture");
    if (profilePictureTitleIndex !== -1) {
      const profilePicVisibilityIdx = profilePictureTitleIndex + 48;
      const profilePicVisibilityStr = profilePicVisibilityIdx >= 0 && profilePicVisibilityIdx < flattenDeepRes.length
        ? flattenDeepRes[profilePicVisibilityIdx]
        : null;
      const profilePicVisibility =
        profilePicVisibilityStr && typeof profilePicVisibilityStr === "string" && profilePicVisibilityStr.toLowerCase().includes("visible to anyone")
        ? "public"
        : "private";
      const profilePicUrlIdx = profilePictureTitleIndex + 4;
      const profilePicUrl =
        profilePicUrlIdx >= 0 && profilePicUrlIdx < flattenDeepRes.length
          ? flattenDeepRes[profilePicUrlIdx]
          : null;
      profile.profilePicture = {
        value: (profilePicUrl && typeof profilePicUrl === "string" ? profilePicUrl : undefined),
        visibility: profilePicVisibility,
      };
    }

    const genderIndex = flattenDeepRes.findIndex(
      (e) => typeof e === "string" && e === "Gender"
    );
    if (genderIndex !== -1) {
      const genderValueIdx = genderIndex + 37;
      const gender = genderValueIdx < flattenDeepRes.length
        ? flattenDeepRes[genderValueIdx]
        : null;
      const genderVisibilityIdx = genderIndex + 53;
      const genderVisibilityStr = genderVisibilityIdx >= 0 && genderVisibilityIdx < flattenDeepRes.length
        ? flattenDeepRes[genderVisibilityIdx]
        : null;
      const genderVisibility =
        genderVisibilityStr && typeof genderVisibilityStr === "string" && genderVisibilityStr.toLowerCase().includes("visible to anyone")
        ? "public"
        : "private";

      profile.gender = {
        value: (gender && typeof gender === "string" ? gender : undefined),
        visibility: genderVisibility,
      };
    }

    const birthdayIndex = flattenDeepRes.findIndex(
      (e) => typeof e === "string" && e === "Birthday"
    );
    if (birthdayIndex !== -1) {
      const birthdayValueIdx = birthdayIndex + 37;
      const birthday = birthdayValueIdx < flattenDeepRes.length
        ? flattenDeepRes[birthdayValueIdx]
        : null;
      const birthdayVisibilityIdx = birthdayIndex + 53;
      const birthdayVisibilityStr = birthdayVisibilityIdx >= 0 && birthdayVisibilityIdx < flattenDeepRes.length
        ? flattenDeepRes[birthdayVisibilityIdx]
        : null;
      const birthdayVisibility =
        birthdayVisibilityStr && typeof birthdayVisibilityStr === "string" && birthdayVisibilityStr.toLowerCase().includes("visible to anyone")
        ? "public"
        : "private";

      profile.birthday = {
        value: (birthday && typeof birthday === "string" ? birthday : undefined),
        visibility: birthdayVisibility,
      };
    }

    profile.emails = {};

    const googleAccountEmailIndex = flattenDeepRes.findIndex(
      (e) => typeof e === "string" && e === "Google Account email"
    );
    if (googleAccountEmailIndex !== -1) {
      const googleAccountEmailValueIdx = googleAccountEmailIndex + 23;
      const googleAccountEmail = googleAccountEmailValueIdx < flattenDeepRes.length
        ? flattenDeepRes[googleAccountEmailValueIdx]
        : null;
      const googleAccountEmailVisibilityIdx = googleAccountEmailIndex + 39;
      const googleAccountEmailVisibilityStr = googleAccountEmailVisibilityIdx >= 0 && googleAccountEmailVisibilityIdx < flattenDeepRes.length
        ? flattenDeepRes[googleAccountEmailVisibilityIdx]
        : null;
      const googleAccountEmailVisibility =
        googleAccountEmailVisibilityStr && typeof googleAccountEmailVisibilityStr === "string" && googleAccountEmailVisibilityStr.toLowerCase().includes("visible to anyone")
        ? "public"
        : "private";
      profile.emails!.googleAccountEmail = {
        value: (googleAccountEmail && typeof googleAccountEmail === "string" ? googleAccountEmail : undefined),
        visibility: googleAccountEmailVisibility,
      };
    }

    // To edit emails "profile/email/edit?index=1",

    const emails = [] as Array<{
      value: string;
      visibility: GoogleProfileInfoVisibility;
    }>;
    if (googleAccountEmailIndex !== -1) {
      for (let i = googleAccountEmailIndex + 1; i < flattenDeepRes.length; i++) {
        if (
          !!flattenDeepRes[i] &&
          typeof flattenDeepRes[i] === "string" &&
          (flattenDeepRes[i] as string) === "Email"
        ) {
          const emailValueIdx = i + 23;
          const email = emailValueIdx < flattenDeepRes.length
            ? flattenDeepRes[emailValueIdx]
            : null;
          const emailVisibilityIdx = i + 39;
          const emailVisibilityStr = emailVisibilityIdx >= 0 && emailVisibilityIdx < flattenDeepRes.length
            ? flattenDeepRes[emailVisibilityIdx]
            : null;
          const emailVisibility =
            emailVisibilityStr && typeof emailVisibilityStr === "string" && emailVisibilityStr.toLowerCase().includes("visible to anyone")
            ? "public"
            : "private";
          if (email && typeof email === "string") {
            emails.push({
              value: email,
              visibility: emailVisibility,
            });
          }
        }
      }
    }
    profile.emails!.otherEmails = emails;

    const placesIndex = flattenDeepRes.findIndex(
      (e) => typeof e === "string" && e.startsWith("Places ")
    );
    if (placesIndex !== -1) {
      const currPlace = (flattenDeepRes[placesIndex] as string)?.replace(
        "Places ",
        ""
      );
      const placesVisibilityIdx = placesIndex - 2;
      const placesVisibilityStr = placesVisibilityIdx >= 0 && placesVisibilityIdx < flattenDeepRes.length
        ? flattenDeepRes[placesVisibilityIdx]
        : null;
      const placesVisibility =
        placesVisibilityStr && typeof placesVisibilityStr === "string" && placesVisibilityStr.toLowerCase().includes("visible to anyone")
        ? "public"
        : "private";
      profile.places = {
        current: currPlace,
        visibility: placesVisibility,
      };

      // find previous places
      const prevPlaceIndex = flattenDeepRes.findIndex(
        (e) => typeof e === "string" && e.startsWith("Previous: ")
      );
      if (prevPlaceIndex !== -1) {
        const prevPlace = (flattenDeepRes[prevPlaceIndex] as string)?.replace(
          "Previous: ",
          ""
        );
        const allPreviousPlaces = prevPlace?.split(";").map((e) => e.trim());
        profile.places!.previous = allPreviousPlaces;
      }
    }

    const occupationIndex = flattenDeepRes.findIndex(
      (e) => typeof e === "string" && e.startsWith("Occupation ")
    );
    if (occupationIndex !== -1) {
      const occupation = (flattenDeepRes[occupationIndex] as string)?.replace(
        "Occupation ",
        ""
      );
      const occupationVisibilityIdx = occupationIndex - 2;
      const occupationVisibilityStr = occupationVisibilityIdx >= 0 && occupationVisibilityIdx < flattenDeepRes.length
        ? flattenDeepRes[occupationVisibilityIdx]
        : null;
      const occupationVisibility =
        occupationVisibilityStr && typeof occupationVisibilityStr === "string" && occupationVisibilityStr.toLowerCase().includes("visible to anyone")
        ? "public"
        : "private";
      profile.occupation = {
        value: occupation,
        visibility: occupationVisibility,
      };
    }

    return profile;
  } catch (e) {
    console.error("OAP: Google error scraping profile info: " + e);
    return { error: "OAP: Google error scraping profile info: " + (e as Error).message };
  }
};
