import {
  GoogleScanResults,
  GoogleScanType,
  GoogleThirdPartyApp,
  ScanResults,
} from "@/app/scripts/oap/types";
import {
  runGoogleDeviceIDCheck,
  runGoogleOAPCheck,
  runGoogleProfileInfoCheck,
  runGoogleSecurityDetailsCheck,
  runGoogleThirdpartyAppsCheck,
} from "./oap-google";
import { runDeleteConnection } from "./delete-connection";

import { runDeleteDeviceSession, scrapeDeviceSessionIDs } from "./devices";
import { setScanInProgress } from "./utils";

// verify script is loaded
console.log(
  "OAP: content-oap-google.js script loaded at",
  new Date().toISOString()
);

async function runOAPCheckWithOnly(runOnly: GoogleScanType, debugRandomFailure?: boolean, debugForceCompleteFail?: boolean): Promise<{
  success: boolean;
  error?: string;
  results?: ScanResults;
  deviceIDs?: string[];
}> {
  return runOAPCheck(runOnly, undefined, debugRandomFailure, debugForceCompleteFail);
}

async function runOAPCheckWithIgnored(ignored: GoogleScanType[], debugRandomFailure?: boolean, debugForceCompleteFail?: boolean): Promise<{
  success: boolean;
  error?: string;
  results?: ScanResults;
  deviceIDs?: string[];
}> {
  return runOAPCheck(undefined, ignored, debugRandomFailure, debugForceCompleteFail);
}

async function runOAPCheck(runOnly?: GoogleScanType, ignore?: GoogleScanType[], debugRandomFailure?: boolean, debugForceCompleteFail?: boolean): Promise<{
  success: boolean;
  error?: string;
  results?: ScanResults;
  deviceIDs?: string[];
}> {
  setScanInProgress(true);

  console.debug("OAP: runOAPCheck called with debugRandomFailure =", debugRandomFailure, "debugForceCompleteFail =", debugForceCompleteFail);

  // Check if we should force a complete failure
  if (debugForceCompleteFail) {
    console.error("OAP: [DEBUG] Forcing complete scan failure");
    setScanInProgress(false);
    throw new Error("OAP: [DEBUG] Simulated complete scan failure for testing error UI");
  }

  try {
    const pageUrl = `${window.location.protocol}//${window.location.hostname}`;
    if (!runOnly) {
      console.debug("OAP: Running OAP check for Google");
      const { scanResults, deviceIDs } = await runGoogleOAPCheck(pageUrl, ignore, debugRandomFailure || false);
      console.debug("OAP: Google check completed successfully", {
        scanResults,
        deviceIDs,
      });
      setScanInProgress(false);
      return { success: true, results: scanResults, deviceIDs };
    }

    console.debug("OAP: Running ONLY OAP check for Google", { runOnly });

    switch (runOnly) {
      case "thirdPartyApps": {
        const results = await runGoogleThirdpartyAppsCheck(debugRandomFailure || false);
        console.debug("OAP: Google check completed successfully", results);
        setScanInProgress(false);
        return { success: true, results };
      }
      case "profileInfo": {
        const results = await runGoogleProfileInfoCheck(debugRandomFailure || false);
        console.debug("OAP: Google check completed successfully", results);
        setScanInProgress(false);
        return { success: true, results };
      }
      case "securityDetails": {
        const results = await runGoogleSecurityDetailsCheck(debugRandomFailure || false);
        console.debug("OAP: Google check completed successfully", results);
        setScanInProgress(false);
        return { success: true, results };
      }
      case "deviceSessions": {
        // rescan device sessions
        // const results = await runGoogleDeviceSessionsCheck()
        // console.debug('OAP: Google check completed successfully', results)
        const deviceIDs = await scrapeDeviceSessionIDs()
        console.debug("OAP: Google check completed successfully", { deviceIDs });
        setScanInProgress(false);
        return { success: true, deviceIDs };
      }
      default:
        console.error("OAP: Unknown runOnly value", { runOnly });
        setScanInProgress(false);
        return { success: false, error: "Unknown runOnly value" };
    }
  } catch (error) {
    console.error("OAP: Error during Google check:", error);
    setScanInProgress(false);
    return {
      success: false,
      error: error instanceof Error ? error.message : String(error),
    };
  }
}

async function runDeviceIDScan(
  deviceID: string
): Promise<{ success: boolean; error?: string; results?: ScanResults }> {
  try {
    console.debug(`OAP: Running device ID scan: ${deviceID}`);
    const scanResults = await runGoogleDeviceIDCheck(deviceID);
    console.debug(
      `OAP: Google device ID scan completed successfully: ${deviceID}`,
      { scanResults }
    );
    return { success: true, results: scanResults };
  } catch (error) {
    console.error(`OAP: Error during device ID scan: ${deviceID}`, error);
    return {
      success: false,
      error: error instanceof Error ? error.message : String(error),
    };
  }
}

async function deleteConnection(app: GoogleThirdPartyApp): Promise<boolean> {
  console.debug("OAP: Deleting connection", app);

  try {
    await runDeleteConnection(app);
    console.debug("OAP: Connection deleted", app);
    return true;
  } catch (err) {
    console.error("Error occurred while deleting connection", err);
    return false;
  }
}

async function deleteDeviceSession(deviceID: string): Promise<boolean> {
  try {
    const success = await runDeleteDeviceSession(deviceID);
    console.debug(
      `OAP: Google device ID delete completed successfully: ${deviceID}`,
      { success }
    );
    return success;
  } catch (error) {
    console.error(`OAP: Error during device ID scan: ${deviceID}`, error);
    return false;
  }
}

async function cancelScan() {
  console.debug("OAP: Cancelling scan");
  setScanInProgress(false);
}

// Auto-run when script is injected via chrome.scripting.executeScript
console.log(
  "OAP: Script execution context - document.readyState:",
  document.readyState,
  "location:",
  window.location.href
);
// register the runOAPCheck function in the window object. This is used by the OAPOrchestrator to run the OAP check.
// @ts-ignore
window.runOAPCheck = runOAPCheck;
// @ts-ignore
window.runOAPCheckWithOnly = runOAPCheckWithOnly;
// @ts-ignore
window.runOAPCheckWithIgnored = runOAPCheckWithIgnored;
// @ts-ignore
window.runDeviceIDScan = runDeviceIDScan;
// @ts-ignore
window.deleteConnection = deleteConnection;
// @ts-ignore
window.deleteDeviceSession = deleteDeviceSession;
// @ts-ignore
window.cancelScan = cancelScan;

export { runOAPCheck };
